// --- CONFIGURACIÓN DEL CORRELATIVO AUTOMÁTICO EN EL NAVEGADOR ---
if (!localStorage.getItem("correlativoCotizacion")) {
  localStorage.setItem("correlativoCotizacion", "1001");
}

// Función central para calcular subtotales y totales al instante en la pantalla
function calcular() {
  let filas = document.querySelectorAll("#cotizacion tbody tr");
  let total = 0;
  
  filas.forEach(fila => {
    let cantidad = parseFloat(fila.querySelector(".input-cantidad").value) || 0;
    let precio = parseFloat(fila.querySelector(".input-precio").value) || 0;
    let subtotal = cantidad * precio;
    
    fila.querySelector(".subtotal").textContent = subtotal.toFixed(2);
    total += subtotal;
  });
  
  document.getElementById("total").textContent = total.toFixed(2);
}

// Función para añadir nuevas filas clonando la estructura base
function agregarFila() {
  let tbody = document.querySelector("#cotizacion tbody");
  let nuevaFila = tbody.rows[0].cloneNode(true);
  
  nuevaFila.querySelectorAll("input").forEach(input => input.value = "");
  nuevaFila.querySelector(".input-cantidad").value = "0";
  nuevaFila.querySelector(".input-precio").value = "0";
  nuevaFila.querySelector(".subtotal").textContent = "0.00";
  
  tbody.appendChild(nuevaFila);
}

